  WHERE ((cc.covered_user_id = tarefas.assigned_to) AND (cc.covering_user_id = ( SELECT auth.uid() AS uid)) AND cc.active AND (now() >= cc.valid_from) AND ((cc.valid_until IS NULL) OR (now() <= cc.valid_until)))))));


